fn main() {
    let mut shopping_list: Vec<&str> = Vec::new();
    shopping_list.push("milk");
    shopping_list.push("eggs");

    let mut numbers: Vec<i32> = Vec::new();
    numbers.push(1);
    numbers.push(2);

    println!("Shopping list: {:?}", shopping_list);
    println!("Numbers: {:?}", numbers);
}
